example.code:
{
  "artefact_id": "billing-models",
  "owner": "ruslan@faion.net",
  "django_version": "5.2.1",
  "db_engine": "postgresql",
  "app": "billing",
  "models": [
    {
      "name": "Invoice",
      "extends": "SoftDeletableModel",
      "fields": [
        {"name": "number", "type": "CharField"},
        {"name": "status", "type": "CharField", "choices_class": "InvoiceStatus", "db_index": true, "db_index_reason": "filter+order_by on every list endpoint; cardinality ~5."},
        {"name": "amount", "type": "DecimalField"}
      ],
      "foreign_keys": [
        {"field": "customer", "to": "accounts.Customer", "on_delete": "PROTECT", "reason": "Preserve invoice history when a customer is soft-deleted; compliance retention."}
      ],
      "constraints": [
        {"name": "invoice_amount_positive",  "kind": "CheckConstraint",  "expression": "amount > 0"},
        {"name": "unique_active_invoice_number", "kind": "UniqueConstraint", "fields": ["number"], "condition": "deleted_at IS NULL"}
      ],
      "indexes": [{"fields": ["customer", "created_at"], "reason": "list-by-customer ordered by recent; primary access pattern."}],
      "full_clean_in_service": true,
      "is_pii": false,
      "soft_delete": true
    }
  ],
  "version": "1.0.0",
  "last_reviewed": "2026-05-22"
}
